div.script:
//

  const screeningsElement = document.querySelector('.screenings');
  const screeningElements = document.querySelectorAll('.screening');
  let searchType = "all";
  let filters = {
    "term": null,
    "program": null,
    "piano": false,
    "age": false,
    "guest": false,
    "intro": false,
    "noLedoux": false,
    "noPlateau": false,
    "restored": false,
    "nl": false,
    "fr": false,
    "startDate": null,
    "endDate": null
  };

  const termInput = document.querySelector("input#term");
  termInput.addEventListener("input", (e) => {
    filters.term = termInput.value;
    updateSearch();
  })

  const ageCheckbox = document.querySelector("input#age");
  ageCheckbox.addEventListener("change", (e) => {
    filters.age = ageCheckbox.checked;
    updateSearch();
  })

  const pianoCheckbox = document.querySelector("input#piano");
  pianoCheckbox.addEventListener("change", (e) => {
    filters.piano = pianoCheckbox.checked;
    updateSearch();
  })

  const guestCheckbox = document.querySelector("input#guest");
  guestCheckbox.addEventListener("change", (e) => {
    filters.guest = guestCheckbox.checked;
    updateSearch();
  })

  const restoredCheckbox = document.querySelector("input#restored");
  restoredCheckbox.addEventListener("change", (e) => {
    filters.restored = restoredCheckbox.checked;
    updateSearch();
  })

  const nlCheckbox = document.querySelector("input#nl");
  nlCheckbox.addEventListener("change", (e) => {
    filters.nl = nlCheckbox.checked;
    updateSearch();
  })

  const frCheckbox = document.querySelector("input#fr");
  frCheckbox.addEventListener("change", (e) => {
    filters.fr = frCheckbox.checked;
    updateSearch();
  })

  const programSelect = document.querySelector("select#program");
  programSelect.addEventListener("change", (e) => {
    filters.program = programSelect.value;
    updateSearch();
  })

  const daySelect = document.querySelector("select#daySelect");
  daySelect.addEventListener("change", (e) => {
    const value = daySelect.value;
    const option = daySelect.querySelector(`option[value="${value}"]`)
    filters.startDate = option.getAttribute("data-start-date");
    filters.endDate = option.getAttribute("data-end-date");
    updateSearch();
  })

  const searchTypeSelect = document.querySelector("select.search__select");
  searchTypeSelect.addEventListener("change", (e) => {
    searchType = searchTypeSelect.value;
    updateSearch();
  })

  // const introCheckbox = document.querySelector("input#intro");
  // introCheckbox.addEventListener("change", (e) => {
  //   filters.intro = introCheckbox.checked;
  //   updateSearch();
  // })

  const ledouxCheckbox = document.querySelector("input#ledoux");
  ledouxCheckbox.addEventListener("change", (e) => {
    filters.noLedoux = !ledouxCheckbox.checked;
    updateSearch();
  })

  const plateauCheckbox = document.querySelector("input#plateau");
  plateauCheckbox.addEventListener("change", (e) => {
    filters.noPlateau = !plateauCheckbox.checked;
    updateSearch();
  })

  const updateSearch = () => {
    const searchActive = Object.keys(filters).filter(key => filters[key]).length;
    if (searchActive) {
      screeningsElement.classList.add('search-active');
      findResults();
    } else {
      screeningsElement.classList.remove('search-active');
    }
  }

  const findResults = () => {
    let found = [...events.map(result => result.id)];
    let notFound = [...events];
    Object.keys(filters).forEach(key => {
      let value = filters[key]
      if (typeof filters[key] === "string") {
        value = filters[key] ? filters[key].toLowerCase().trim() : null;
      }
      let keysToSearch = [key]
      if (key === "term") {
        if (searchType === "all") {
          keysToSearch = ["titles", "directors", "cast"]
        } else {
          keysToSearch = [searchType];
        }
      }
      if (value) {
        if (key === "noLedoux" || key === "noPlateau") {
          if (key === "noLedoux") {
            value = "plateau"
          }
          if (key === "noPlateau") {
            value = "ledoux"
          }
          keysToSearch = ["location"]
        }
        let groupResults = [];
        keysToSearch.forEach(keyToSearch => {
          const results = events.filter(event => {
            if (event[keyToSearch]) {
              let eventValue = event[keyToSearch];
              if (typeof eventValue === "string") {
                eventValue = event[keyToSearch].toLowerCase().trim();
                if (eventValue.indexOf(value) > -1) {
                  return true;
                }
              } else {
                if (eventValue == value) {
                  return true
                }
              }
            } else if (keyToSearch === "startDate") {
              return true;
            } else if (keyToSearch === "endDate") {
              const startDate = filters["startDate"];
              const endDate = filters["endDate"];
              console.log(startDate, endDate)

              if (event.date >= parseInt(startDate) && event.date < parseInt(endDate)) {
                return true;
              }
            }
            return false;
          }).map(result => result.id);
          // const resultsNotFound = events.filter(event => !event[keyToSearch].indexOf(value.toLowerCase().trim()) > -1).map(result => result.id);
          groupResults = [...groupResults, ...results];
        })
        found = [...new Set(groupResults.filter(el => found.includes(el)))]
      }
    })

    showResults(found)
  }

  const showResults = (found) => {
    screeningElements.forEach(element => {
      element.classList.remove('screening-active');
    })
    found.forEach(result => {
      const screening = screeningsElement.querySelector(`[data-id="${result}"]`);
      screening.classList.add("screening-active")
    })
  }

  document.addEventListener('DOMContentLoaded', function () {
    let yTarget = document.querySelector('[data-date="' + document.querySelector('#calendar').getAttribute('data-today') + '"]').offsetTop
    window.scrollTo({top: yTarget, behavior: 'smooth'});
  }, false);


